/**
 * Tests for cross-platform path utilities (CC 2.1.78 additions)
 *
 * CC 2.1.78 added CLAUDE_PLUGIN_DATA — a persistent directory that survives
 * plugin updates. getPluginDataDir / getSessionStorageDir / getAnalyticsStorageDir
 * must prefer that directory when the env var is present and fall back to the
 * legacy project-local path otherwise.
 */

import { describe, it, expect, afterEach } from 'vitest';
import {
  getPluginDataDir,
  getSessionStorageDir,
  getAnalyticsStorageDir,
  getProjectDir,
  getPluginRoot,
  safeProjectDir,
} from '../../lib/paths.js';

// Helpers ────────────────────────────────────────────────────────────────────

function setPluginData(val: string): void {
  process.env.CLAUDE_PLUGIN_DATA = val;
}

function clearPluginData(): void {
  delete process.env.CLAUDE_PLUGIN_DATA;
}

// ============================================================================
// getPluginDataDir (CC 2.1.78)
// ============================================================================

describe('getPluginDataDir (CC 2.1.78)', () => {
  afterEach(() => {
    clearPluginData();
  });

  it('returns null when CLAUDE_PLUGIN_DATA is not set', () => {
    clearPluginData();
    expect(getPluginDataDir()).toBeNull();
  });

  it('returns the env var value when CLAUDE_PLUGIN_DATA is set', () => {
    setPluginData('/Users/dev/.claude/plugins/data/ork-orchestkit');
    expect(getPluginDataDir()).toBe('/Users/dev/.claude/plugins/data/ork-orchestkit');
  });

});

// ============================================================================
// getSessionStorageDir (CC 2.1.78)
// ============================================================================

describe('getSessionStorageDir (CC 2.1.78)', () => {
  afterEach(() => {
    clearPluginData();
    delete process.env.CLAUDE_PROJECT_DIR;
  });

  it('returns exact PLUGIN_DATA/sessions path when set', () => {
    setPluginData('/plugin/data');
    // Use path.join for cross-platform correctness
    const { join } = require('node:path');
    expect(getSessionStorageDir()).toBe(join('/plugin/data', 'sessions'));
  });

  it('falls back to project-local .claude/memory/sessions when env var absent', () => {
    clearPluginData();
    process.env.CLAUDE_PROJECT_DIR = '/test/project';
    const { join } = require('node:path');
    expect(getSessionStorageDir()).toBe(join('/test/project', '.claude', 'memory', 'sessions'));
  });
});

